import{_ as i,X as a,Y as l,a3 as e}from"./framework-abbf9d44.js";const h="/assets/image-20241022192309601-11ccce11.png",r="/assets/image-20241022192348391-a40b252a.png",d="/assets/image-20241022192418134-a45326e2.png",s={},n=e('<h2 id="_3d打印背景知识" tabindex="-1"><a class="header-anchor" href="#_3d打印背景知识" aria-hidden="true">#</a> 3D打印背景知识</h2><ul><li>3D打印三个阶段，包括等材制造、减材制造和增材制造。 <ul><li>等材制造： 例如打铁 铁锅等</li><li>减材制造：例如机床切割等</li><li>增材制造：3D打印</li></ul></li><li>建模常见的两种方式。3D设计，3D扫描</li><li>四种常见的3D打印技术：光固化成型（SLA）、激光选区烧结、三维印刷（3DP）和熔融堆积（FDM）。</li></ul><h2 id="使用场景" tabindex="-1"><a class="header-anchor" href="#使用场景" aria-hidden="true">#</a> 使用场景</h2><h3 id="当前的" tabindex="-1"><a class="header-anchor" href="#当前的" aria-hidden="true">#</a> 当前的</h3><ol><li>建筑行业</li><li>玩具</li><li>航空 航天 （未来的月球基地）</li><li>影视制作（道具）</li><li>汽车制作（特别是设计和概念车）</li><li>医疗行业 （比如牙齿等定制器械</li><li>文物（博物馆 复刻等</li><li>食品行业（巧克力、蛋糕等等）</li></ol><h3 id="未来的" tabindex="-1"><a class="header-anchor" href="#未来的" aria-hidden="true">#</a> 未来的</h3><ol><li>机器普及且成熟，大家可以导出买原料打印自己想要的东西/事物</li><li>打印器官等</li><li>太空基地构建</li><li>打印衣服（目前已经可以打印，比如鞋）</li><li>4D打印，添加了时间维度，再特定的时间/场景 又不同的形态</li></ol><h2 id="软件" tabindex="-1"><a class="header-anchor" href="#软件" aria-hidden="true">#</a> 软件</h2><ul><li>123D design （ 上手快，停更很久了，不推荐）</li><li>DX （ 新手上手难度太高）</li><li>Blender （开源的，个人喜欢这个，小白从这里开始入门了）</li><li>Rhino（犀牛，专业）</li><li>Fusion 360 （据说整合了123D的功能）</li></ul><h2 id="工具准备" tabindex="-1"><a class="header-anchor" href="#工具准备" aria-hidden="true">#</a> 工具准备</h2><h3 id="测量" tabindex="-1"><a class="header-anchor" href="#测量" aria-hidden="true">#</a> 测量</h3><ul><li>游标卡尺</li><li>卷尺</li></ul><h3 id="拆支撑" tabindex="-1"><a class="header-anchor" href="#拆支撑" aria-hidden="true">#</a> 拆支撑</h3><ul><li><p>尖嘴钳</p></li><li><p>木工凿</p></li></ul><p>用到其他工具如水口钳那代表耗材问题，或者机器出问题，拓竹的支撑就没难拆过）</p><h3 id="防翘边" tabindex="-1"><a class="header-anchor" href="#防翘边" aria-hidden="true">#</a> 防翘边</h3><p>纹理板刚开始不建议使用，如果平台不粘了将板子洗一洗。（拓竹要是防翘边，那一定是有问题，换耗材，清理热床）</p><img src="'+h+'" alt="image-20241022192309601" style="zoom:50%;"><h3 id="粘合" tabindex="-1"><a class="header-anchor" href="#粘合" aria-hidden="true">#</a> 粘合</h3><ul><li>慢干型：AB胶（哥俩好）、木工胶</li><li>速干型：502、亚克力胶水（推荐）</li></ul><img src="'+r+'" alt="image-20241022192348391" style="zoom:50%;"><h3 id="表面处理" tabindex="-1"><a class="header-anchor" href="#表面处理" aria-hidden="true">#</a> 表面处理</h3><ul><li>细节处理：刻刀、美工刀、打火机（防风/喷枪)</li><li>表面打磨：砂纸、锉刀</li><li>层纹覆盖：（拓竹没啥必要，还是老样子，要外观上光固化）</li></ul><img src="'+d+'" alt="image-20241022192418134" style="zoom:50%;"><h3 id="上色" tabindex="-1"><a class="header-anchor" href="#上色" aria-hidden="true">#</a> 上色</h3><ul><li>普通：丙烯颜料、画笔、</li><li>进阶：喷漆，自喷漆、喷笔+水性漆</li></ul><p>拓竹的AMS系统直接多色打印够用</p><h3 id="保养" tabindex="-1"><a class="header-anchor" href="#保养" aria-hidden="true">#</a> 保养</h3><ul><li>六角扳手</li><li>螺丝刀套装</li><li>润滑剂</li></ul>',29),t=[n];function c(o,u){return a(),l("div",null,t)}const m=i(s,[["render",c],["__file","简单介绍.html.vue"]]);export{m as default};
